/// <summary>
/// this class will handle logic for add to bucket for new container or existing containers
/// </summary>
public final class ETGITMAddBucketContainerFormHandlerOut
{
    private FormRun thisFormRun;
    private FormDataSource tmpCreatorTable_ds, tmpCreatorLine_ds, containers_ds;

    private ITMTable itmTable;
    private ITMTmpCreatorLine tmpCreatorLine;
    private ITMContainers itmContainers;
    private boolean addToExistingContainers;
    private boolean operationCompleted;
    private boolean batchFeatureEnabled;

}

Method.Source:
public static ETGITMAddBucketContainerFormHandlerOut newFromForm(FormRun _element)
{
    ETGITMAddBucketContainerFormHandlerOut form = new ETGITMAddBucketContainerFormHandlerOut();

    form.InitFromFormRun(_element);

    return form;
}

private void initFromFormRun(FormRun _formRun)
{
    thisFormRun = _formRun;

    tmpCreatorLine_ds = thisFormRun.dataHelper().FindDataSource(formDataSourceStr(ETGITMAddBucketContainerOut, ITMTmpCreatorLine));
    containers_ds = thisFormRun.dataHelper().FindDataSource(formDataSourceStr(ETGITMAddBucketContainerOut, ITMContainers));
    batchFeatureEnabled = FeatureStateProvider::isFeatureEnabled(ITMAddToContainerBatchJobFeature::instance());
}

public ITMTable parmITMTable(ITMTable _itmTable = itmTable)
{
    itmTable = _itmTable;

    return itmTable;
}

public ITMContainers parmITMContainers(ITMContainers _itmContainers = itmContainers)
{
    itmContainers = _itmContainers;

    return itmContainers;
}

public ITMTmpCreatorLine parmTmpCreatorLine(ITMTmpCreatorLine _tmpCreatorLine = tmpCreatorLine)
{
    tmpCreatorLine = _tmpCreatorLine;

    return tmpCreatorLine;
}

public boolean parmAddToExistingContainers(boolean _addToExistingContainers = addToExistingContainers)
{
    addToExistingContainers = _addToExistingContainers;

    return addToExistingContainers;
}

public boolean parmOperationCompleted(boolean _operationCompleted = operationCompleted)
{
    operationCompleted = _operationCompleted;

    return operationCompleted;
}

private str createContainersFormName()
{
    return formStr(ETGITMContainersCreateFromBucketOut);
}

public void removeBucket(ITMTmpCreatorTable _tmpCreatorTable)
{
    ETGITMCreatorTableGeneration::removeFromBucketFromForm(_tmpCreatorTable, tmpCreatorLine);

    this.refreshCallingDatasource();
}

public boolean parmBatchFeatureEnabled()
{
    return batchFeatureEnabled;
}

public void createContainersForm()
{
    if (batchFeatureEnabled)
    {
        this.parmOperationCompleted(false);
        Args args = new Args();
        args.caller(this);
        new MenuFunction(menuItemActionStr(ETGITMCreatorCreateShipmentOut), MenuItemType::Action).run(args);

        if (this.parmOperationCompleted())
        {
            this.addQtyIfSplitQty();

            this.removeTmpCreatorLine();

            this.updateInventTransIdInBucket();

            this.refreshCallingDatasource();
        }
    }
    else
    {
        Args        args = new Args();
        args.name(this.createContainersFormName());
        args.caller(this);
        FormRun     createContainers;
        createContainers = classfactory.formRunClass(args);
        createContainers.init();
        createContainers.run();
        createContainers.wait();
    }
}

public void folioForm()
{
    Args args = new Args();

    args.record(this.parmITMTable());

    new MenuFunction(menuItemDisplayStr(ITMFolioTableListPage), MenuItemType::Display).run(args);
}

public void addContainers(boolean _addToExistContainer = false)
{
    ETGITMCreatorCreateShipmentOut::createShipmentFromShipEditor(
        tmpCreatorLine, 
        ITMTable, 
        ITMContainers, 
        _addToExistContainer);
}

public void refreshCallingDatasource()
{
    tmpCreatorLine_ds.research();

    containers_ds.research(); 
}

public void removeTmpCreatorLine()
{
    delete_from tmpCreatorLine
        where tmpCreatorLine.AddedToBucket && tmpCreatorLine.Selected;
}

public void updateInventTransIdInBucket()
{
    ITMTmpCreatorLine ITMTmpCreatorLineUpdate;
    InventTransOrigin InventTransOrigin;

    ITMTmpCreatorLineUpdate.setTmpData(tmpCreatorLine);

    ttsbegin;
    while select forupdate ITMTmpCreatorLineUpdate
        where ITMTmpCreatorLineUpdate.AddedToBucket == NoYes::Yes 
            && ITMTmpCreatorLineUpdate.Selected == NoYes::No
            notexists join InventTransOrigin
                where InventTransOrigin.InventTransId == ITMTmpCreatorLineUpdate.InventTransId
    {
        InventTransId InventTransIdNonITM = this.getInventTransIdNonITM(ITMTmpCreatorLineUpdate.InventTransType, ITMTmpCreatorLineUpdate.InventTransId);

        if(InventTransIdNonITM)
        {
            ITMTmpCreatorLineUpdate.InventTransId = InventTransIdNonITM;
            ITMTmpCreatorLineUpdate.update();
        }
    }
    ttscommit;
}

public void addQtyIfSplitQty() 
{
    ITMTmpCreatorLine ITMTmpCreatorLineGroup, ITMTmpCreatorLineLocal;

    ITMTmpCreatorLineGroup.setTmpData(tmpCreatorLine);

    ITMTmpCreatorLineLocal.setTmpData(tmpCreatorLine);

    while select sum(TransferQty), sum(InventQty), sum(PurchQty), InventTransId, Close, ShipDataArea, InventTransType from ITMTmpCreatorLineGroup
        group by InventTransId, Close, ShipDataArea, InventTransType
        where ITMTmpCreatorLineGroup.Selected == NoYes::Yes
            && ITMTmpCreatorLineGroup.AddedToBucket == NoYes::Yes
            && ITMTmpCreatorLineGroup.TransferQty > 0
            && ITMTmpCreatorLineGroup.TransferQty < ITMTmpCreatorLineGroup.InventQty
    {
        select tmpCreatorLine where tmpCreatorLine.InventTransId == ITMTmpCreatorLineGroup.InventTransId;

        InventTransId InventTransIdNonITM = this.getInventTransIdNonITM(ITMTmpCreatorLineGroup.InventTransType, ITMTmpCreatorLineGroup.InventTransId);

        if(InventTransIdNonITM)
        {
            buf2Buf(tmpCreatorLine, ITMTmpCreatorLineLocal);
            ITMTmpCreatorLineLocal.PurchQty = ITMTmpCreatorLineGroup.PurchQty - ITMTmpCreatorLineGroup.TransferQty;

            InventMovement movement = InventTransOrigin::findByInventTransId(InventTransIdNonITM).inventMovement();
            InventUnitId   inventUnitId = movement.inventTableInvent().UnitId;
            if (inventUnitId
                && ITMTmpCreatorLineLocal.PurchUnit 
                && InventUnitId != ITMTmpCreatorLineLocal.PurchUnit)
          //todo test
            if(ETGOTMAddToBucketUnitConversionFlight::instance().isEnabled())
            {
                ITMTmpCreatorLineLocal.InventQty = ITMTmpCreatorLineGroup.InventQty - EcoResProductUnitConverter::convertGivenUnitSymbolsForReleasedProduct(
                                                                                                    movement.itemId(),
                                                                                                    movement.inventDimId(),
                                                                                                    ITMTmpCreatorLineGroup.TransferQty,
                                                                                                    ITMTmpCreatorLineLocal.PurchUnit,
                                                                                                    InventUnitId,
                                                                                                    NoYes::Yes);
            }
            else
            {
                ITMTmpCreatorLineLocal.InventQty = ITMTmpCreatorLineGroup.InventQty - ITMTmpCreatorLineGroup.TransferQty ;
            }

            ITMTmpCreatorLineLocal.TransferQty = ITMTmpCreatorLineLocal.PurchQty;
            ITMTmpCreatorLineLocal.InventTransId = InventTransIdNonITM;
            ITMTmpCreatorLineLocal.Selected = NoYes::No;
            ITMTmpCreatorLineLocal.doInsert();
        }

    }
}

public InventTransId getInventTransIdSales(InventTransId _orderlineInventTransId)
{
    SalesDeliverySchedule salesDeliverySchedule, salesDeliveryScheduleOrderLine;
    ITMLine ITMLine;

    select DeliveryLine from salesDeliverySchedule
        where salesDeliverySchedule.OrderLine == _orderlineInventTransId
        notexists join ITMLine where ITMLine.InventTransId == salesDeliverySchedule.Deliveryline;

    if(!salesDeliverySchedule.Deliveryline)
    {
        select OrderLine from salesDeliveryScheduleOrderLine
            where salesDeliveryScheduleOrderLine.DeliveryLine == _orderlineInventTransId
            join DeliveryLine from salesDeliverySchedule
                where salesDeliverySchedule.OrderLine == salesDeliveryScheduleOrderLine.OrderLine
                notexists join ITMLine 
                    where ITMLine.InventTransId == salesDeliverySchedule.Deliveryline;
    }

    return salesDeliverySchedule.Deliveryline;
}

public InventTransId getInventTransIdNonITM(InventTransType _inventTransType, InventTransId _inventTransId)
{
    switch(_inventTransType)
    {
        case InventTransType::Sales :
            return this.getInventTransIdSales(_inventTransId);
        case InventTransType::TransferOrderShip :
            return _inventTransId;
        default : 
            return '';				
    }
}

public void validateTmpCreatorLine()
{
    ITMLine ITMLine;

    ttsbegin;

    while select forupdate tmpCreatorLine
        where tmpCreatorLine.AddedToBucket && tmpCreatorLine.Selected
        exists join ITMLine
            where ITMLine.InventTransId == tmpCreatorLine.InventTransId
            && ITMLine.ShipDataArea == tmpCreatorLine.ShipDataArea
    {
        warning(strFmt("@InboundTransportationManagement:ItemAlreadyAddedToShipment", tmpCreatorLine.ItemId));

        tmpCreatorLine.delete();
    }

    ttscommit;
}

public void initCreateContainerForm()
{
    this.validateTmpCreatorLine();

    this.refreshCallingDatasource();
}

public void addToNewContainerProcess(ITMContainers _itmContainers, boolean _addToExistContainer = false)
{
    try
    {
        this.parmITMContainers(_itmContainers);

        this.validateTmpCreatorLine();

        this.addContainers(_addToExistContainer);

        this.addQtyifSplitQty();

        this.removeTmpCreatorLine();

        this.updateInventTransIdInBucket();

        this.refreshCallingDatasource();
    }
    catch(Exception::Error)
    {
        this.refreshCallingDatasource();
    }
}
